window.__QUIZ_DATA__=[{"id":"theory>Chemistry>1996>1>a","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES","question":"List two gases which are monoatomic","images":[],"marking_scheme":"-Helium   -Neon   -Xenon  -Argon (i.e. all noble gases)","marks":"8","difficulty":"1"},{"id":"theory>Chemistry>1996>1>b>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HYDROGEN CHLORIDE GAS","question":"Mention one gas which forms:  dense white fumes with ammonia vapour","images":[],"marking_scheme":"Hydrogen chloride gas","marks":"6","difficulty":"2"},{"id":"theory>Chemistry>1996>1>b>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HALOGENS","question":"Mention one gas which forms:  yellow precipitate with ammoniacal silver trioxonitrate (V) solution.","images":[],"marking_scheme":"-Ethyne   -propyne   -but-1-nye.","marks":"6","difficulty":"2"},{"id":"theory>Chemistry>1996>2>a","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STATES OF MATTER : KINETIC THEORY OF MATTER.","question":"State three postulates of the kinetic theory","images":[],"marking_scheme":"-Particles of matter are in constant or continuous motion  -The particles move randomly in straight lines and colliding with one another  -The forces of attraction or repulsion are negligible  -The collision is perfectly elastic","marks":"12","difficulty":"2"},{"id":"theory>Chemistry>1996>2>b>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STATES OF MATTER : GASES","question":"Name the process involved in the;  spread of the smell of a perfume across a room","images":[],"marking_scheme":"Diffusion","marks":"4","difficulty":"1"},{"id":"theory>Chemistry>1996>2>b>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Name the process involved in the;  decrease in the yellow of a liquid after exposure in an open vessel.","images":[],"marking_scheme":"Oxidation.  Oxidation is a chemical reaction where a substance  loses electrons, often reacting with oxygen in the air. Many yellow-coloured compounds, especially organic ones, can oxidize when exposed to air, leading to changes in their structure and a consequent loss of colour. This process is common in various substances, including some organic dyes, natural pigments, and food items.","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>1996>3>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"What is the anhydride of each of the following acids?:  H2SO4","images":[],"marking_scheme":"SO3","marks":"4","difficulty":"3"},{"id":"theory>Chemistry>1996>3>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"What is the anhydride of each of the following acids?:  HNO3","images":[],"marking_scheme":"N2O3 or NO2","marks":"4","difficulty":"3"},{"id":"theory>Chemistry>1996>3>b>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Classify each of the: following as normal salt/acid salt/basic salt/double salt  Sodium hydrogentrioxocarbonate (IV)","images":[],"marking_scheme":"Acid salt","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>1996>3>b>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Classify each of the: following as normal salt/acid salt/basic salt/double salt    Iron (III) chloride","images":[],"marking_scheme":"Normal salt","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>1996>3>b>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Classify each of the: following as normal salt/acid salt/basic salt/double salt  Sodium ethanoate.","images":[],"marking_scheme":"Normal salt.","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>1996>4>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HYDROGEN SULPHIDE","question":"State two physical properties of hydrogen sulphide","images":[],"marking_scheme":"-colourless gas at room temperature  -repulsive or smell like rotten egg  -extremely toxic and poisonous  -moderatrly soluble in water and denser than air","marks":"10","difficulty":"1"},{"id":"theory>Chemistry>1996>4>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HYDROGEN SULPHIDE","question":"Name the laboratory equipment used for intermittent production of hydrogen sulphide","images":[],"marking_scheme":"Kipp's apparatus","marks":"5","difficulty":"1"},{"id":"theory>Chemistry>1996>4>b","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : HYDROGEN SULPHIDE","question":"What property of hydrogen sulphide is illustrated in the reaction represented by the following equation?    H2S(g) + 2NaOH(aq) \u2192 Na2S(aq) + H2O(l)","images":[],"marking_scheme":"Acidic properties","marks":"5","difficulty":"2"},{"id":"theory>Chemistry>1996>5>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"","topic":"PERIODIC CHEMISTRY : ELECTRON CONFIGURATION","question":"The elements listed below to the same group in the Periodic Table 9F  17CI 35Br 53I.  Write the electronic structure of the first member","images":[],"marking_scheme":"1s22s22p5 or 2,7","marks":"4","difficulty":"1"},{"id":"theory>Chemistry>1996>5>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"The elements listed below to the same group in the Periodic Table 9F  17CI 35Br 53I.    What is the family name of the elements.","images":[],"marking_scheme":"Halogen","marks":"4","difficulty":"1"},{"id":"theory>Chemistry>1996>5>a>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I","question":"The elements listed below to the same group in the Periodic Table 9F  17CI  35Br  53I.  Which of the elements has the strongest oxidizing ability?","images":[],"marking_scheme":"Fluorine of F","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>1996>5>b>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"","topic":"CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.","question":"Which of the chlorides would exist as discrete molecules?","images":[],"marking_scheme":"BCl4","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>1996>5>b>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.","question":"What type of bonding holds atoms of A and chlorine together in ACI?","images":[],"marking_scheme":"Ionic or Electronic bonding","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>1996>5>b>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"Which of the chlorides would be a good conductor of electricity?","images":[],"marking_scheme":"ACl","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>1996>6>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.","question":"Name the class of oxides to which copper (II) oxide belongs.","images":[],"marking_scheme":"Basic oxide.  These are oxides that react with acids to form salts and water. They are typically formed by metals, especially those from groups 1 and 2 of the periodic table, as well as some transition metals like copper. Copper (II) oxide reacts with acids such as hydrochloric acids to form copper (II) chloride and water.  CuO + 2HCl \u2192 CuCl2 + H2O","marks":"5","difficulty":"1"},{"id":"theory>Chemistry>1996>6>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.","question":"Give the reason why copper (II) oxide increases in mass on exposure to the atmosphere","images":[],"marking_scheme":"It is hygroscopic or absorbs water from atmosphere on exposure (but does not form solutions)","marks":"5","difficulty":"2"},{"id":"theory>Chemistry>1996>6>a>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Write an equation to show the action of dilute hydrochloric acid on copper (II) oxide.","images":[],"marking_scheme":"CuO + 2HCI \u2192CuCl2 + H2O","marks":"5","difficulty":"2"},{"id":"theory>Chemistry>1996>6>b","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION","question":"List two methods of removing total hardness from water.","images":[],"marking_scheme":"-Use of washing soda  -Use of ion-exchange resin/permutit process  -Distillation or fractional distillation.","marks":"5","difficulty":"2"},{"id":"theory>Chemistry>1996>7>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"FINAL","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Use the following energy profile diagram to answer Questions (a) to (c) below.      From the diagram, determine the value of the; enthalpy of the reaction","images":["data:image/png;base64,"],"marking_scheme":"Enthalpy = (50 -150) KJ/mol = - 100 KJ/mol","marks":"5","difficulty":"3"},{"id":"theory>Chemistry>1996>7>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"FINAL","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Use the following energy profile diagram to answer Questions (a) to (c) below.    From the diagram, determine the value of the; activation energy of the reaction.","images":["data:image/png;base64,"],"marking_scheme":"Activation energy = (350 - 150) KJ/mol = 200KJ","marks":"5","difficulty":"2"},{"id":"theory>Chemistry>1996>7>b","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Use the following energy profile diagram to answer Questions (a) to (c) below.    State whether the profile diagram is for an endothermic reaction or an exothermic reaction.","images":["data:image/png;base64,"],"marking_scheme":"It is for an exothermic reaction","marks":"5","difficulty":"2"},{"id":"theory>Chemistry>1996>7>c","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Use the following energy profile diagram to answer Questions (a) to (c) below.    What name is given to substances which can provide an alternative pathway for the reaction?","images":["data:image/png;base64,"],"marking_scheme":"Catalyst or promoters or inhibitors.","marks":"5","difficulty":"2"},{"id":"theory>Chemistry>1996>8>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY","question":"Give the name of the:  process for obtaining ethanol from sugars;","images":[],"marking_scheme":"Fermentation","marks":"4","difficulty":"1"},{"id":"theory>Chemistry>1996>8>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS","question":"Give the name of the:  compound produced when ethanol undergoes bacterial oxidation.","images":[],"marking_scheme":"Ethanoic acid or ethanal","marks":"4","difficulty":"1"},{"id":"theory>Chemistry>1996>8>a>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : AMINO ACIDS","question":"Give the name of the:  enzyme in yeast which catalyses the conversion of maltose to glucose.","images":[],"marking_scheme":"Maltase","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>1996>8>b>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOLS","question":"Write the structural formula of ethanol","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"1"},{"id":"theory>Chemistry>1996>8>b>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS","question":"Name the organic product formed when propanoic acid reacts with ethanol.","images":[],"marking_scheme":"EthylPropanoate","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>1996>9>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : SYNTHETIC POLYMERS","question":"State the monomer units of polyethene;","images":[],"marking_scheme":"Ethene or C2H4","marks":"7","difficulty":"1"},{"id":"theory>Chemistry>1996>9>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES","question":"State the monomer units of cellulose","images":[],"marking_scheme":"Glucose C6H12O6.","marks":"7","difficulty":"1"},{"id":"theory>Chemistry>1996>9>b","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL","question":"Name the two fuels obtained when steam and air are passed over red-hot coke.","images":[],"marking_scheme":"Producer gas and water gas.","marks":"6","difficulty":"2"},{"id":"theory>Chemistry>1996>10>a","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"a","group":"FINAL","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Determine the oxidation number of manganese in MnO4-","images":[],"marking_scheme":"X + (4X - 2) = -1    X - 8 = -1    X = +8 - 1 = +7","marks":"8","difficulty":"3"},{"id":"theory>Chemistry>1996>10>b>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS","question":"List two metals that are extracted from their ores by electrolysis","images":[],"marking_scheme":"-Aluminium   -calcium   -sodium   -potassium   -magnesium","marks":"6","difficulty":"2"},{"id":"theory>Chemistry>1996>10>b>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES","question":"Give one difference between a conductor and an electrolyte","images":[],"marking_scheme":"ConductorsElectrolytes-They are not decomposed by electric current Decomposed by the passage of current.-Decomposed by the passage of current-They are usually solids-They are molten or aqueous solution-Free electrons conduct the current-Mobile ions conduct the current.","marks":"6","difficulty":"1"},{"id":"theory>Chemistry>1996>11>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Explain what is meant by an effective collision","images":[],"marking_scheme":"An effective collision is one that results in the formation of the product(s) into chemical reactions","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>1996>11>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"What does each term represent in the following expression? \u0394G = \u0394H \u2014 T\u0394S","images":[],"marking_scheme":"\u0394 G Stands for free energy change.   \u0394H stands for change in heat content or enthalpy;   T\u0394S stands for products of temperature and entropy change","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>1996>11>a>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"What deduction can be made about a system given that the value of its \u0394G is zero?","images":[],"marking_scheme":"The system is in a state of (dynamic) equilibrium","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>1996>11>b>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"State Le Chatelier's principle.","images":[],"marking_scheme":"Le Chatelier's principle states that if a chemical system is in equilibrium and one of the factors involved in the system is altered, the equilibrium position will shift so as to annul the effect of the change.","marks":"3","difficulty":"1"},{"id":"theory>Chemistry>1996>11>b>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"Suggest three conditions necessary for maximum yield of A2B in the reaction represented by the following equation 2A2(g) + B2(g) \u21cc 2A2B(g) \u0394H = xkj.","images":[],"marking_scheme":"-Increase in the pressure or Concentration  -Lower the temperature.  -Remove the product as it is formed","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>1996>11>b>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"Write an expression for the equilibrium constant of the reaction in (b)(ii) above.","images":[],"marking_scheme":"KC = [A2B]2/[A2]2[B2]","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>1996>11>c>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Give the reason why a log of wood of a given mass does not burn out as quickly as sawdust of the same mass, under the same conditions.","images":[],"marking_scheme":"Sawdust has a larger surface area than a log of wood of the same mass. Since reaction rate increases with increase in surface area hence the sawdust burns out faster.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1996>11>c>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"List two examples of chemical reactions that are catalyzed by light","images":[],"marking_scheme":"-Decomposition of silver halides/trioxonitrate (v)   -Reaction of methane with chlorine.  -Decomposition of hydrogen peroxide  -Chlorination of Benzene  -Photosynthesis in plants","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>1996>12>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Give one major use of alkanes.","images":[],"marking_scheme":"-for heating and cooking purpose  -as fuel  -main component of natural gas","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>1996>12>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Name the simplest alkane that exhibits structural isomerism","images":[],"marking_scheme":"Butane","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>1996>12>a>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"FINAL","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Determine the molar mass of an alkane that is represented as CxH22. [H = 1, C = 12]","images":[],"marking_scheme":"General formula CnH2n +2.  2x + 2 = 22; 2x = 22-2; x = 10; Formula is C10H22 and Molar mass = (12 x 10) + (1 x 22) = 142g","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>1996>12>a>iv","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKENES~~CHEMISTRY OF CARBON COMPOUNDS : ALKYNES","question":"List two types of chemical reactions which the alkenes and alkynes undergo.","images":[],"marking_scheme":"-Addition reaction   -combustion  -polymerization  -oxidation and reduction","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>1996>12>b>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS","question":"State the type of reaction involved in the conversion of palm oil to margarine.","images":[],"marking_scheme":"-Hydrogenation or addition of hydrogen","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>1996>12>b>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS","question":"Give the reason why the palm oil for manufacturing margarine is first treated activated charcoal","images":[],"marking_scheme":"To decolorize or bleach it","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>1996>12>b>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS","question":"What is commonly used to catalyse the conversion of vegetable oils to margarine?","images":[],"marking_scheme":"Finely divided nickel","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>1996>12>c>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : FATS/OILS","question":"Name the class of organic compounds to which oils belong.","images":[],"marking_scheme":"Alkanoates","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>1996>12>c>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Describe briefly procedure for the manufacture of soap from vegetable oils","images":[],"marking_scheme":"The process of making soap is known as saponification. Sodium hydroxide is dissolved in water and added to the warm oil. This hydrolyzes the oil to form carboxylate salts (soap) and glycerol.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>1996>12>c>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Explain why the presence of calcium ions in domestic water supply wastes soap.","images":[],"marking_scheme":"he presence of Ca2+ in water causes hardness. The ion react with soap to form a precipitate (scum) until all the Ca2+ is removed. The soap does not form a lather and is thus wasted","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>1996>13>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"List three factors which affect the discharge of ions during electrolysis","images":[],"marking_scheme":"-Position of ions in the activity series or electrochemical series  -The concentration of ion in the electrolyte  -Nature of electrode.","marks":"6","difficulty":"2"},{"id":"theory>Chemistry>1996>13>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"Describe in outline, the purification of copper by electrolysis.","images":[],"marking_scheme":"The impure copper is made up of the anode in electrolyte while strips of pure copper act as cathode. The electrolyte is copper (II) tetraoxosulphate (VI) solution. During electrolysis, the impure copper anode dissolves and copper ions are transferred to the cathode when they are discharged and deposited on the pure copper.    At the anode Cu  \u2192 Cu2+ + 2e+  At the cathode Cu2+ + 2e2+ \u2192  Cu","marks":"6","difficulty":"3"},{"id":"theory>Chemistry>1996>13>b>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"The following data were collected in an experiment on electrolysis:  Current flowing(amps)Time of current flow (secs)Quantity of electricity (coulombs)Mass of metal M deposited (gram)0.209000.060.2018000.120.2027000.180.2036000.24    Copy and complete the table above calculating the quantity of electricity passed in each case","images":[],"marking_scheme":"Current flowing(amps)Time of current flow (secs)Quantity of electricity (coulombs)Mass of metal M deposited (gram)0.209001800.060.2018003600.120.2027005400.180.2036007200.24","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>1996>13>b>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"The following data were collected in an experiment on electrolysis:  Current flowing(amps)Time of current flow (secs)Quantity of electricity (coulombs)Mass of metal M deposited (gram)0.209000.060.2018000.120.2027000.180.2036000.24Plot a graph of the mass of M deposited against the quantity of electricity passed.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>1996>13>b>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"FINAL","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"The following data were collected in an experiment on electrolysis:  Current flowing(amps)Time of current flow (secs)Quantity of electricity (coulombs)Mass of metal M deposited (gram)0.209000.060.2018000.120.2027000.180.2036000.24From the graph, determine the mass of M that was deposited by the same current passing for 20 minutes.","images":[],"marking_scheme":"Quantity of electricity passing for 20 minutes = (20 x 60) Sec. X 0.2 = 240 coulombs. From the graph, mass of M deposited by 240 coulombs is 0.08g","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>1996>13>b>iv","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"The following data were collected in an experiment on electrolysis:  Current flowing(amps)Time of current flow (secs)Quantity of electricity (coulombs)Mass of metal M deposited (gram)0.209000.060.2018000.120.2027000.180.2036000.24From the shape of the graph, which of the laws of electrolysis does the experiment verify?","images":[],"marking_scheme":"Faraday's 1st law of electrolysis.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>1996>14>a>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"What is an acid?","images":[],"marking_scheme":"An acid is a compound which produces hydroxonium ions in aqueous solutions","marks":"3","difficulty":"1"},{"id":"theory>Chemistry>1996>14>a>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"List three chemical properties of tetraoxosulphate (VI) acid","images":[],"marking_scheme":"-Reacts with metal above hydrogen in dilute form to liberate hydrogen  -Reacts with bases to form salt and water only  -It liberates CO2 from trioxocarbonate (IV) Salts  -Acts as an oxidising agent with metals and non-metals  -Acts a dehydrating agent","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>1996>14>a>iii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Give two uses of tetraoxosulphate (VI) acid.","images":[],"marking_scheme":"-For making fertilizer   -For making drugs in pharmaceutical industries  -production of soap and detergents  -as a dessicant for drying many gases","marks":"3","difficulty":"1"},{"id":"theory>Chemistry>1996>14>b>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"Describe a suitable laboratory procedure for preparing a sample of zinc tetraoxosulphate (VI) crystals, starting from zinc oxide.","images":[],"marking_scheme":"Put dil. tetraoxosulphate (VI) acid in a beaker and add zinc oxide until more of the oxide dissolves. Filter off excess oxide. Pour filtrate in an evaporating dish and heat to concentrate it. Cool to obtain crystals. Filter off crystals and dry between filter paper.","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>1996>14>b>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS","question":"Write two equations to show why zinc oxide is classified as an amphoteric oxide.","images":[],"marking_scheme":"ZnO + 2HCI \u2192 ZnCl2 + H2O    ZnO + 2NaOH \u2192 Na2ZnO2 + H2O","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>1996>14>c>i","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Zinc reacts with copper (II) tetraoxosulphate (VI) according to the following equation: Zn + CuSO4 -> ZnSO4 + Cu  State the type of reaction involved","images":[],"marking_scheme":"Displacement or Redox reaction","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>1996>14>c>ii","subject":"Chemistry","year":"1996","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Zinc reacts with copper (II) tetraoxosulphate (VI) according to the following equation: Zn + CuSO4 -> ZnSO4 + Cu    Determine the mass of zinc that would react completely with 8.0g of copper (II) tetraoxosulphate (VI). [CuSO4 = 160; Zn = 65]","images":[],"marking_scheme":"From the equation 160g of CuSO4 reacts with 65g of Zn   8g of CuSO4 would react with    65\u00d78/160=3.25g","marks":"2","difficulty":"3"}];